def gen(rng, size):
    while True:
        if rng.random() < 0.5:
            R, C = 1, rng.randint(3, 6)
        else:
            R, C = 2, 3
        g = [['.' for _ in range(C)] for _ in range(R)]
        for r in range(R):
            for c in range(C):
                if rng.random() < 0.15:
                    g[r][c] = '#'
        floors = [(r, c) for r in range(R) for c in range(C) if g[r][c] == '.']
        if len(floors) < 3:
            continue
        rng.shuffle(floors)
        (mr, mc), (cr, cc), (fr, fc) = floors[0], floors[1], floors[2]
        g[mr][mc] = 'M'; g[cr][cc] = 'C'; g[fr][fc] = 'F'
        grid = [''.join(row) for row in g]
        return [grid, rng.randint(1, 3), rng.randint(1, 3)]

