import sys
from functools import lru_cache
class Solution:
    def canMouseWin(self, grid, catJump, mouseJump):
        sys.setrecursionlimit(1000000)
        R = len(grid); C = len(grid[0])
        cells = []; idx = {}
        for r in range(R):
            for c in range(C):
                if grid[r][c] != '#':
                    idx[(r, c)] = len(cells); cells.append((r, c))
        N = len(cells)
        M = Cc = F = 0
        for (r, c), i in idx.items():
            ch = grid[r][c]
            if ch == 'M': M = i
            elif ch == 'C': Cc = i
            elif ch == 'F': F = i
        dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]
        def reach(i, jump):
            r0, c0 = cells[i]; res = [i]
            for dr, dc in dirs:
                for k in range(1, jump + 1):
                    nr, nc = r0 + dr * k, c0 + dc * k
                    if 0 <= nr < R and 0 <= nc < C and grid[nr][nc] != '#':
                        res.append(idx[(nr, nc)])
                    else:
                        break
            return res
        mreach = [reach(i, mouseJump) for i in range(N)]
        creach = [reach(i, catJump) for i in range(N)]
        LIMIT = 2 * N * N
        @lru_cache(maxsize=None)
        def solve(m, c, turn, ply):
            if c == F or c == m:
                return False
            if m == F:
                return True
            if ply >= LIMIT:
                return False
            if turn == 0:
                for nm in mreach[m]:
                    if solve(nm, c, 1, ply + 1):
                        return True
                return False
            else:
                for nc in creach[c]:
                    if not solve(m, nc, 0, ply + 1):
                        return False
                return True
        return solve(M, Cc, 0, 0)

