from collections import deque
class Solution:
    def canMouseWin(self, grid, catJump, mouseJump):
        R = len(grid); C = len(grid[0])
        cells = []; idx = {}
        for r in range(R):
            for c in range(C):
                if grid[r][c] != '#':
                    idx[(r, c)] = len(cells); cells.append((r, c))
        N = len(cells)
        M = Cc = F = 0
        for (r, c), i in idx.items():
            ch = grid[r][c]
            if ch == 'M': M = i
            elif ch == 'C': Cc = i
            elif ch == 'F': F = i
        dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]
        def reach(i, jump):
            r0, c0 = cells[i]; res = [i]
            for dr, dc in dirs:
                for k in range(1, jump + 1):
                    nr, nc = r0 + dr * k, c0 + dc * k
                    if 0 <= nr < R and 0 <= nc < C and grid[nr][nc] != '#':
                        res.append(idx[(nr, nc)])
                    else:
                        break
            return res
        mreach = [reach(i, mouseJump) for i in range(N)]
        creach = [reach(i, catJump) for i in range(N)]
        MOUSE, CAT = 1, 2
        color = [[[0, 0] for _ in range(N)] for _ in range(N)]
        degree = [[[len(mreach[mi]), len(creach[ci])] for ci in range(N)] for mi in range(N)]
        q = deque()
        for mi in range(N):
            for ci in range(N):
                for t in (0, 1):
                    if ci == F or ci == mi:
                        color[mi][ci][t] = CAT; q.append((mi, ci, t))
                    elif mi == F:
                        color[mi][ci][t] = MOUSE; q.append((mi, ci, t))
        while q:
            mi, ci, t = q.popleft(); w = color[mi][ci][t]
            if t == 0:
                for cp in creach[ci]:
                    if color[mi][cp][1] == 0:
                        if w == CAT:
                            color[mi][cp][1] = CAT; q.append((mi, cp, 1))
                        else:
                            degree[mi][cp][1] -= 1
                            if degree[mi][cp][1] == 0:
                                color[mi][cp][1] = MOUSE; q.append((mi, cp, 1))
            else:
                for mp in mreach[mi]:
                    if color[mp][ci][0] == 0:
                        if w == MOUSE:
                            color[mp][ci][0] = MOUSE; q.append((mp, ci, 0))
                        else:
                            degree[mp][ci][0] -= 1
                            if degree[mp][ci][0] == 0:
                                color[mp][ci][0] = CAT; q.append((mp, ci, 0))
        return color[M][Cc][0] == MOUSE

