var canMouseWin = function(grid, catJump, mouseJump) {
    const R = grid.length, C = grid[0].length;
    const cells = []; const idx = {};
    const key = (r, c) => r * C + c;
    for (let r = 0; r < R; r++) {
        for (let c = 0; c < C; c++) {
            if (grid[r][c] !== '#') { idx[key(r, c)] = cells.length; cells.push([r, c]); }
        }
    }
    const N = cells.length;
    let M = 0, Cc = 0, F = 0;
    for (let i = 0; i < N; i++) {
        const [r, c] = cells[i]; const ch = grid[r][c];
        if (ch === 'M') M = i; else if (ch === 'C') Cc = i; else if (ch === 'F') F = i;
    }
    const dirs = [[0, 1], [0, -1], [1, 0], [-1, 0]];
    const reach = (i, jump) => {
        const [r0, c0] = cells[i]; const res = [i];
        for (const [dr, dc] of dirs) {
            for (let k = 1; k <= jump; k++) {
                const nr = r0 + dr * k, nc = c0 + dc * k;
                if (nr >= 0 && nr < R && nc >= 0 && nc < C && grid[nr][nc] !== '#') res.push(idx[key(nr, nc)]);
                else break;
            }
        }
        return res;
    };
    const mreach = [], creach = [];
    for (let i = 0; i < N; i++) { mreach.push(reach(i, mouseJump)); creach.push(reach(i, catJump)); }
    const MOUSE = 1, CAT = 2;
    const color = Array.from({length: N}, () => Array.from({length: N}, () => [0, 0]));
    const degree = Array.from({length: N}, (_, mi) => Array.from({length: N}, (_, ci) => [mreach[mi].length, creach[ci].length]));
    const q = [];
    for (let mi = 0; mi < N; mi++) {
        for (let ci = 0; ci < N; ci++) {
            for (let t = 0; t < 2; t++) {
                if (ci === F || ci === mi) { color[mi][ci][t] = CAT; q.push([mi, ci, t]); }
                else if (mi === F) { color[mi][ci][t] = MOUSE; q.push([mi, ci, t]); }
            }
        }
    }
    let head = 0;
    while (head < q.length) {
        const [mi, ci, t] = q[head++]; const w = color[mi][ci][t];
        if (t === 0) {
            for (const cp of creach[ci]) {
                if (color[mi][cp][1] === 0) {
                    if (w === CAT) { color[mi][cp][1] = CAT; q.push([mi, cp, 1]); }
                    else { if (--degree[mi][cp][1] === 0) { color[mi][cp][1] = MOUSE; q.push([mi, cp, 1]); } }
                }
            }
        } else {
            for (const mp of mreach[mi]) {
                if (color[mp][ci][0] === 0) {
                    if (w === MOUSE) { color[mp][ci][0] = MOUSE; q.push([mp, ci, 0]); }
                    else { if (--degree[mp][ci][0] === 0) { color[mp][ci][0] = CAT; q.push([mp, ci, 0]); } }
                }
            }
        }
    }
    return color[M][Cc][0] === MOUSE;
};
